module counter10bit_up (
    input clk,
    input rst,
    input en,
    output [9:0] q
);

    reg [9:0] unused_q_reg;

    always @(posedge clk or posedge rst) begin
        if (rst)
            unused_q_reg <= 10'b0000000000;
        else if (en)
            unused_q_reg <= unused_q_reg + 1;
    end

    assign q = unused_q_reg;

endmodule
